

'use client';

import { doc, setDoc, getDoc, serverTimestamp } from 'firebase/firestore';
import { getFirestoreDb } from './firebase';
import type { UserProfile } from './types';


async function getClientDb() {
    return getFirestoreDb();
}


export async function updateUserProfile(uid: string, data: Partial<UserProfile>) {
  const db = await getClientDb();
  const userRef = doc(db, 'users', uid);
  await setDoc(userRef, { 
    ...data,
    lastLogin: serverTimestamp(),
    // Set default values for new users
    isSubscribed: data.isSubscribed ?? false,
    credits: data.credits ?? 1,
    createdAt: data.createdAt ?? serverTimestamp(),
  }, { merge: true });
}


export async function checkUserSubscription(uid: string): Promise<UserProfile | null> {
  const db = await getClientDb();
  const userRef = doc(db, 'users', uid);
  const docSnap = await getDoc(userRef);

  if (docSnap.exists()) {
    const data = docSnap.data();
    return {
        ...data,
        createdAt: data.createdAt?.toDate ? data.createdAt.toDate().toISOString() : new Date().toISOString(),
        lastLogin: data.lastLogin?.toDate ? data.lastLogin.toDate().toISOString() : new Date().toISOString(),
    } as UserProfile;
  } else {
    return null;
  }
}


export async function activateUserSubscription(uid: string) {
    const db = await getClientDb();
    const userRef = doc(db, 'users', uid);

    const docSnap = await getDoc(userRef);
    if (!docSnap.exists()) {
        // This case should ideally not happen if updateUserProfile is called on login/signup
        // But as a fallback, we create the profile.
        await updateUserProfile(uid, { isSubscribed: true, credits: 15 });
        return;
    }
    
    const currentCredits = docSnap.data().credits || 0;

    await setDoc(userRef, {
        isSubscribed: true,
        credits: currentCredits + 15,
    }, { merge: true });
}
